<script setup lang="ts">import { computed } from 'vue';import MarkdownIt from 'markdown-it';const props=defineProps<{content:string}>();const md=new MarkdownIt({html:false,linkify:true,breaks:true});const fallback=md.renderer.rules.link_open;md.renderer.rules.link_open=(tokens,idx,options,env,self)=>{tokens[idx].attrSet('target','_blank');tokens[idx].attrSet('rel','noopener noreferrer');return fallback?fallback(tokens,idx,options,env,self):self.renderToken(tokens,idx,options);};const escaped=(value:string)=>value.replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]||c));const html=computed(()=>{const source=props.content||'';const rendered=md.render(source);const token=/\[文件:([^\]]+)\]([^|\n]+)(?:\|([\d.]+))?/g;return rendered.replace(token,(_all,path,name,size)=>`<a class="file-token" href="/files/download.json?path=${encodeURIComponent(path)}" target="_blank" rel="noopener"><b>卷</b><span>${escaped(name.trim())}</span>${size?`<small>${Math.max(1,Math.round(Number(size)/1024))}KB</small>`:''}</a>`);});</script>
<template><div class="markdown" v-html="html"></div></template>
